import psycopg2
from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/api/v1/data', methods=['GET'])
def get_data():
    table_name = request.args.get('table_name')
    column_names = request.args.get('column_names')
    filter_conditions = request.args.get('filter_conditions')

    # Prevent SQL injection by using parameterized queries
    query = "SELECT {} FROM {} WHERE {};".format(
        ", ".join(column_names), table_name, filter_conditions)

    try:
        conn = psycopg2.connect("dbname=mydatabase user=myuser password=mypassword")
        cur = conn.cursor()
        cur.execute(query)
        results = cur.fetchall()
        return jsonify(results)
    except (Exception, psycopg2.DatabaseError) as error:
        print(error)
        return jsonify({'message': 'An error occurred while retrieving data.'})